CREATE TABLE IF NOT EXISTS events (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), title_zh text NOT NULL, title_en text, summary_zh text NOT NULL, summary_en text, category text NOT NULL CHECK (category IN ('regulatory', 'partnership', 'product', 'funding', 'market', 'policy', 'technical', 'other')), importance smallint NOT NULL DEFAULT 3 CHECK (importance BETWEEN 1 AND 4), entity_names text[] DEFAULT '{}', source_urls text[] NOT NULL DEFAULT '{}', source_count smallint NOT NULL DEFAULT 1, v1_status text CHECK (v1_status IN ('matched', 'partial', 'no_match') OR v1_status IS NULL), published_at timestamptz NOT NULL, pushed_to_tg boolean NOT NULL DEFAULT false, included_in_daily boolean NOT NULL DEFAULT false, included_in_weekly boolean NOT NULL DEFAULT false, created_at timestamptz NOT NULL DEFAULT now());
